@* Displays a single task with title, assignee, priority badge, due date, and move buttons *@

<div class="task-card">
    <div class="task-card-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge @GetPriorityClass()">@Task.Priority</span>
    </div>
    <div class="task-card-body">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-card-actions">
        @if (CanMoveLeft)
        {
            <button class="btn btn-sm btn-outline-secondary" @onclick="OnMoveLeft" disabled="@IsMoving">← Move Left</button>
        }
        @if (CanMoveRight)
        {
            <button class="btn btn-sm btn-outline-secondary" @onclick="OnMoveRight" disabled="@IsMoving">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeftClicked { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRightClicked { get; set; }

    private bool IsMoving;

    private string GetPriorityClass() => Task.Priority switch
    {
        "High" => "priority-high",
        "Medium" => "priority-medium",
        "Low" => "priority-low",
        _ => ""
    };

    private async System.Threading.Tasks.Task OnMoveLeft()
    {
        IsMoving = true;
        await OnMoveLeftClicked.InvokeAsync(Task);
        IsMoving = false;
    }

    private async System.Threading.Tasks.Task OnMoveRight()
    {
        IsMoving = true;
        await OnMoveRightClicked.InvokeAsync(Task);
        IsMoving = false;
    }
}

@* Inline form for creating a new task within a column *@

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm add-task-btn" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="Priority">
                <option value="">Select Priority</option>
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="DueDate" />
        </div>
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="text-danger small mb-2">@ErrorMessage</div>
        }
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@IsSaving">Save</button>
            <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool IsVisible;
    private bool IsSaving;
    private string Title = "";
    private string Assignee = "";
    private string Priority = "";
    private DateTime DueDate = DateTime.Today;
    private string? ErrorMessage;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Title) || string.IsNullOrWhiteSpace(Assignee) || string.IsNullOrWhiteSpace(Priority))
        {
            ErrorMessage = "Title, assignee, and priority are required.";
            return;
        }

        IsSaving = true;
        await OnTaskCreated.InvokeAsync(new TaskItem(0, Title.Trim(), Assignee.Trim(), Priority, DueDate, ""));
        IsSaving = false;
        ResetForm();
        IsVisible = false;
    }

    private void ResetForm()
    {
        Title = "";
        Assignee = "";
        Priority = "";
        DueDate = DateTime.Today;
        ErrorMessage = null;
    }
}

