    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnAddTask { get; set; }

    private async Task HandleMoveLeft(TaskItem task) => await OnMoveLeft.InvokeAsync(task);
    private async Task HandleMoveRight(TaskItem task) => await OnMoveRight.InvokeAsync(task);
    private async Task HandleTaskCreated(TaskItem task) => await OnAddTask.InvokeAsync(task);
}
"}

