<div class="board-stats">
    <div class="stat-item">
        <span class="stat-value">@Total</span>
        <span class="stat-label">Total</span>
    </div>
    <div class="stat-item">
        <span class="stat-value">@ToDo</span>
        <span class="stat-label">To Do</span>
    </div>
    <div class="stat-item">
        <span class="stat-value">@InProgress</span>
        <span class="stat-label">In Progress</span>
    </div>
    <div class="stat-item">
        <span class="stat-value">@Done</span>
        <span class="stat-label">Done</span>
    </div>
    <div class="stat-item stat-overdue">
        <span class="stat-value">@Overdue</span>
        <span class="stat-label">Overdue</span>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = [];

    private int Total => Tasks.Count;
    private int ToDo => Tasks.Count(t => t.Status == "To Do");
    private int InProgress => Tasks.Count(t => t.Status == "In Progress");
    private int Done => Tasks.Count(t => t.Status == "Done");
    private int Overdue => Tasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");
}
