+    [Parameter] public bool CanMoveRight { get; set; }
+    [Parameter] public EventCallback<TaskItem> OnMoveLeftClicked { get; set; }
+    [Parameter] public EventCallback<TaskItem> OnMoveRightClicked { get; set; }
+
+    private bool IsMoving;
+
+    private string GetPriorityClass() => Task.Priority switch
+    {
+        "High" => "priority-high",
+        "Medium" => "priority-medium",
+        "Low" => "priority-low",
+        _ => ""
+    };
+
+    private async System.Threading.Tasks.Task OnMoveLeft()
+    {
+        IsMoving = true;
+        await OnMoveLeftClicked.InvokeAsync(Task);
+        IsMoving = false;
+    }
+
+    private async System.Threading.Tasks.Task OnMoveRight()
+    {
+        IsMoving = true;
+        await OnMoveRightClicked.InvokeAsync(Task);
+        IsMoving = false;
+    }
+}
