@* Inline form for creating a new task within a column *@

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm add-task-btn" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="Priority">
                <option value="">Select Priority</option>
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="DueDate" />
        </div>
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="text-danger small mb-2">@ErrorMessage</div>
        }
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@IsSaving">Save</button>
            <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool IsVisible;
    private bool IsSaving;
    private string Title = "";
    private string Assignee = "";
    private string Priority = "";
    private DateTime DueDate = DateTime.Today;
    private string? ErrorMessage;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Title) || string.IsNullOrWhiteSpace(Assignee) || string.IsNullOrWhiteSpace(Priority))
        {
            ErrorMessage = "Title, assignee, and priority are required.";
            return;
        }

        IsSaving = true;
        await OnTaskCreated.InvokeAsync(new TaskItem(0, Title.Trim(), Assignee.Trim(), Priority, DueDate, ""));
        IsSaving = false;
        ResetForm();
        IsVisible = false;
    }

    private void ResetForm()
    {
        Title = "";
        Assignee = "";
        Priority = "";
        DueDate = DateTime.Today;
        ErrorMessage = null;
    }
}

