/* Board layout */
.kanban-board {
    display: flex;
    gap: 1rem;
    overflow-x: auto;
    padding-bottom: 1rem;
}

/* Stats bar */
.board-stats {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.stat-item {
    display: flex;
    flex-direction: column;
    align-items: center;
}

.stat-value {
    font-size: 1.5rem;
    font-weight: 700;
}

.stat-label {
    font-size: 0.75rem;
    color: #6c757d;
    text-transform: uppercase;
}

.stat-overdue .stat-value {
    color: #dc3545;
}

/* Search bar */
.board-search {
    margin-bottom: 1rem;
    max-width: 400px;
}

/* Column */
.kanban-column {
    flex: 1 1 0;
    min-width: 280px;
    background: #f1f3f5;
    border-radius: 0.5rem;
    display: flex;
    flex-direction: column;
}

.kanban-column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    border-bottom: 2px solid #dee2e6;
}

.kanban-column-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
}

.kanban-column-body {
    flex: 1;
    padding: 0.5rem;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 100px;
}

.kanban-column-footer {
    padding: 0.5rem;
    border-top: 1px solid #dee2e6;
}

/* Task card */
.task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.75rem;
    box-shadow: 0 1px 2px rgba(0,0,0,0.05);
}

.task-card-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 0.5rem;
}

.task-title {
    font-weight: 600;
    font-size: 0.9rem;
    word-break: break-word;
}

.priority-badge {
    font-size: 0.7rem;
    padding: 0.15rem 0.5rem;
    border-radius: 1rem;
    font-weight: 600;
    white-space: nowrap;
}

.priority-high {
    background: #dc3545;
    color: #fff;
}

.priority-medium {
    background: #ffc107;
    color: #212529;
}

.priority-low {
    background: #28a745;
    color: #fff;
}

.task-card-body {
    display: flex;
    justify-content: space-between;
    font-size: 0.8rem;
    color: #6c757d;
    margin-bottom: 0.5rem;
}

.task-card-actions {
    display: flex;
    gap: 0.375rem;
}

/* Add task form */
.add-task-form {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.75rem;
}

.add-task-btn {
    width: 100%;
}

